mapper.select:
select count(1) from sys_menu m where
	replace(m.menu_url,'/','')=replace(#{menuUrl},'/','')

		AND menu_id != #{menuId}

mapper.update:
	UPDATE sys_menu
	SET
		SORT_NUM = #{sortNum,jdbcType=NUMERIC},
		LAST_UPDATED_BY = #{lastUpdatedBy,jdbcType=NUMERIC},
		LAST_UPDATED_DATE = #{lastUpdatedDate,jdbcType=TIMESTAMP}
 	WHERE MENU_ID = #{menuId,jdbcType=NUMERIC}

	UPDATE sys_menu
		SET
	LEVEL_NUM = #{levelNum,jdbcType=NUMERIC},
	LAST_UPDATED_BY = #{lastUpdatedBy,jdbcType=NUMERIC},
 	LAST_UPDATED_DATE = #{lastUpdatedDate,jdbcType=TIMESTAMP}
	WHERE MENU_ID = #{menuId,jdbcType=NUMERIC}

mapper.select:
SELECT o.ROUTE_ID, r.ROUTE_URL, o.PARENT_ID, o.MENU_ID, o.MENU_NAME FROM sys_behavior_log s ,sys_menu o,sys_route r WHERE s.MENU_ID = o.MENU_ID AND o.route_id = r.route_id AND s.MENU_ID in
#{item}
AND s.USER_ID = #{userId}
GROUP BY s.MENU_ID order by COUNT(s.MENU_ID) DESC limit 0,6
